def _write_text_b64(path, b64):
    path = Path(path)
    if not path.exists():
        path.write_text(base64.b64decode(b64).decode('utf-8'), encoding='utf-8')
        print('embedded', path, flush=True)

def _write_bytes_b64(path, b64):
    path = Path(path)
    if not path.exists():
        path.write_bytes(base64.b64decode(b64))
        print('embedded', path, flush=True)

