def mae(y, p):
    return float(np.mean(np.abs(np.asarray(y, float) - np.asarray(p, float))))

def metrics(y, p):
    m = mae(y, p)
    return {"mae": m, "rae": m / DENOM_RAE}

def print_metric(label, y, p):
    d = metrics(y, p)
    print(f"{label}: MAE={d['mae']:.6f} RAE={d['rae']:.6f}", flush=True)
    return d["mae"]

def align(df, base):
    m = base[["Molecule Name"]].merge(df[["Molecule Name", "pEC50"]], on="Molecule Name", how="left")
    if m["pEC50"].isna().any():
        raise ValueError(f"missing {m['pEC50'].isna().sum()} prediction rows")
    return m["pEC50"].to_numpy(float)

def load_sub(path):
    df = pd.read_csv(path)
    p1 = align(df, phase1)
    pt = align(df, test)
    exact = int(np.isclose(p1, y_phase, atol=1e-10, rtol=0).sum())
    return df, p1, pt, exact

