def simplex_stack(P, y, l2=0.002, max_weight=0.60):
    n = P.shape[1]
    x0 = np.ones(n) / n
    bounds = [(0, max_weight)] * n
    cons = [{"type": "eq", "fun": lambda w: np.sum(w) - 1.0}]
    def obj(w):
        pred = P @ w
        return np.mean(np.abs(y - pred)) + l2 * np.sum(w * w)
    res = minimize(obj, x0, method="SLSQP", bounds=bounds, constraints=cons, options={"maxiter": 1000, "ftol": 1e-10})
    w = np.clip(res.x, 0, max_weight)
    w = w / w.sum()
    return w

