    oof_stack = np.zeros(len(y_phase))
    test_stack_repeats = []
    for tr, va in skf0.split(P_phase, bins):
        w = simplex_stack(P_phase[tr], y_phase[tr], l2=0.006, max_weight=0.55)
        oof_stack[va] = P_phase[va] @ w
        test_stack_repeats.append(P_test @ w)
    stack_test = np.mean(test_stack_repeats, axis=0)
