fp_cache = {}
def mol_from_smi(s):
    return Chem.MolFromSmiles(str(s))

def bit_features(smiles_list):
    rows, fps = [], []
    for i, smi in enumerate(smiles_list):
        mol = mol_from_smi(smi)
        if mol is None:
            morgan = np.zeros(2048, dtype=np.float32)
            maccs = np.zeros(167, dtype=np.float32)
            desc = np.zeros(len(desc_fns), dtype=np.float32)
            fps.append(None)
        else:
            bv = morgan_gen.GetFingerprint(mol)
            fps.append(bv)
            morgan = np.zeros((2048,), dtype=np.int8)
            DataStructs.ConvertToNumpyArray(bv, morgan)
            mk = MACCSkeys.GenMACCSKeys(mol)
            maccs = np.zeros((167,), dtype=np.int8)
            DataStructs.ConvertToNumpyArray(mk, maccs)
            vals = []
            for _, fn in desc_fns:
                try:
                    vals.append(float(fn(mol)))
                except Exception:
                    vals.append(0.0)
            desc = np.array(vals, dtype=np.float32)
        rows.append(np.concatenate([morgan.astype(np.float32), maccs.astype(np.float32), desc]))
        if (i + 1) % 5000 == 0:
            print("featurized", i + 1, "/", len(smiles_list), flush=True)
    return np.vstack(rows), fps

