smiles_to_fp = {s: f for s, f in zip(all_smiles, fps_all)}

def X_for(frame_or_smiles):
    if isinstance(frame_or_smiles, pd.DataFrame):
        smiles = frame_or_smiles["SMILES"].astype(str).tolist()
    else:
        smiles = list(map(str, frame_or_smiles))
    missing = [s for s in smiles if s not in smiles_to_row]
    if missing:
        X_new, fps_new = bit_features(missing)
        start = len(all_smiles)
        # This branch is intentionally simple; for current challenge it should rarely trigger.
        for s, row, fpv in zip(missing, X_new, fps_new):
            smiles_to_row[s] = len(smiles_to_row)
            smiles_to_fp[s] = fpv
        raise RuntimeError("Unexpected new SMILES after all_smiles build; rerun cell.")
    return X_all[[smiles_to_row[s] for s in smiles]]

