print("Aux feature columns:", aux_names, flush=True)

print("\n=== Residual correction search ===", flush=True)

comp_stats_phase = np.column_stack([
    np.mean(P_phase, axis=1),
    np.std(P_phase, axis=1),
    np.min(P_phase, axis=1),
    np.max(P_phase, axis=1),
    np.max(P_phase, axis=1) - np.min(P_phase, axis=1),
])
comp_stats_test = np.column_stack([
    np.mean(P_test, axis=1),
    np.std(P_test, axis=1),
    np.min(P_test, axis=1),
    np.max(P_test, axis=1),
    np.max(P_test, axis=1) - np.min(P_test, axis=1),
])

# Use only compact continuous descriptors in the residual layer.
desc_phase = X_phase[:, -len(desc_fns):]
desc_test = X_test[:, -len(desc_fns):]

F_phase = np.column_stack([
    base_p1,
    comp_stats_phase,
    K_phase,
    A_phase,
    desc_phase,
])
F_test = np.column_stack([
    base_test,
    comp_stats_test,
    K_test,
    A_test,
    desc_test,
])

F_phase = np.nan_to_num(F_phase, nan=np.nanmedian(F_phase, axis=0), posinf=0.0, neginf=0.0)
F_test = np.nan_to_num(F_test, nan=np.nanmedian(F_phase, axis=0), posinf=0.0, neginf=0.0)
resid = y_phase - base_p1

model_factories = {
    "huber": lambda: make_pipeline(StandardScaler(), HuberRegressor(alpha=0.02, epsilon=1.35, max_iter=2000)),
    "ridge": lambda: make_pipeline(StandardScaler(), Ridge(alpha=10.0)),
    "elastic": lambda: make_pipeline(StandardScaler(), ElasticNet(alpha=0.02, l1_ratio=0.20, max_iter=5000)),
    "tiny_lgb": lambda: LGBMRegressor(
        objective="regression_l1",
        n_estimators=100,
        learning_rate=0.025,
        num_leaves=7,
        min_child_samples=28,
        subsample=0.80,
        colsample_bytree=0.75,
        reg_lambda=12.0,
        random_state=44,
        n_jobs=-1,
        verbose=-1,
    ),
}
if XGBRegressor is not None:
    model_factories["tiny_xgb"] = lambda: XGBRegressor(
        objective="reg:absoluteerror",
        n_estimators=120,
        max_depth=2,
        learning_rate=0.025,
        subsample=0.80,
        colsample_bytree=0.70,
        reg_lambda=20.0,
        min_child_weight=12.0,
        random_state=45,
        n_jobs=-1,
        verbosity=0,
    )

split_seeds = [41, 73, 109]
split_sets = [StratifiedKFold(n_splits=5, shuffle=True, random_state=s) for s in split_seeds]

best = None
for model_name, factory in model_factories.items():
    for shrink in [0.25, 0.40, 0.55, 0.70, 0.85]:
        for cap in [0.12, 0.20, 0.28, 0.35, 0.45]:
            repeated_preds = []
            for skf in split_sets:
                oof = np.zeros(len(y_phase), dtype=float)
                for tr, va in skf.split(F_phase, bins):
                    model = factory()
                    model.fit(F_phase[tr], resid[tr])
                    corr = np.clip(model.predict(F_phase[va]), -cap, cap)
                    oof[va] = np.clip(base_p1[va] + shrink * corr, 1.0, 8.5)
                repeated_preds.append(oof)
            avg_oof = np.mean(repeated_preds, axis=0)
            score = mae(y_phase, avg_oof)
            if best is None or score < best["mae"]:
                best = {"mae": score, "model": model_name, "shrink": shrink, "cap": cap, "oof": avg_oof}
                print("new best", best["model"], "shrink", shrink, "cap", cap,
                      "MAE", f"{score:.6f}", "RAE", f"{score / DENOM_RAE:.6f}", flush=True)

cv_mae = print_metric("BEST repeated-CV residual", y_phase, best["oof"])
print("best cfg:", {k: best[k] for k in ["model", "shrink", "cap"]}, flush=True)

print("\n=== Nested anti-overfit audit ===", flush=True)
print(
    "Outer folds never participate in choosing model/shrink/cap. "
    "This is the number to trust most for transfer risk.",
    flush=True,
)

nested_factories = {k: model_factories[k] for k in ["huber", "ridge", "elastic"] if k in model_factories}
if "tiny_xgb" in model_factories:
    nested_factories["tiny_xgb"] = model_factories["tiny_xgb"]
nested_shrinks = [0.25, 0.40, 0.55, 0.70]
nested_caps = [0.12, 0.20, 0.28, 0.35]
outer = StratifiedKFold(n_splits=5, shuffle=True, random_state=909)
nested_oof = np.zeros(len(y_phase), dtype=float)
nested_choices = []
for outer_i, (outer_tr, outer_va) in enumerate(outer.split(F_phase, bins), start=1):
    inner_bins = pd.qcut(y_phase[outer_tr], q=5, labels=False, duplicates="drop")
    inner = StratifiedKFold(n_splits=4, shuffle=True, random_state=3000 + outer_i)
    best_inner = None
    for model_name, factory in nested_factories.items():
        for shrink in nested_shrinks:
            for cap in nested_caps:
                inner_oof = np.zeros(len(outer_tr), dtype=float)
                for itr_rel, iva_rel in inner.split(F_phase[outer_tr], inner_bins):
                    itr = outer_tr[itr_rel]
                    iva = outer_tr[iva_rel]
                    model = factory()
                    model.fit(F_phase[itr], resid[itr])
                    corr = np.clip(model.predict(F_phase[iva]), -cap, cap)
                    inner_oof[iva_rel] = np.clip(base_p1[iva] + shrink * corr, 1.0, 8.5)
                score = mae(y_phase[outer_tr], inner_oof)
                if best_inner is None or score < best_inner[0]:
                    best_inner = (score, model_name, shrink, cap)
    _, model_name, shrink, cap = best_inner
    model = nested_factories[model_name]()
    model.fit(F_phase[outer_tr], resid[outer_tr])
    corr = np.clip(model.predict(F_phase[outer_va]), -cap, cap)
    nested_oof[outer_va] = np.clip(base_p1[outer_va] + shrink * corr, 1.0, 8.5)
    nested_choices.append((model_name, shrink, cap))
    print(
        f"outer fold {outer_i}: chose model={model_name} shrink={shrink} cap={cap} "
        f"inner_MAE={best_inner[0]:.6f}",
        flush=True,
    )

nested_mae = print_metric("HONEST nested-CV residual", y_phase, nested_oof)

print("\n=== Full-fit chosen correction and save ===", flush=True)
chosen_model = model_factories[best["model"]]()
chosen_model.fit(F_phase, resid)
full_corr_phase = np.clip(chosen_model.predict(F_phase), -best["cap"], best["cap"])
full_p1 = np.clip(base_p1 + best["shrink"] * full_corr_phase, 1.0, 8.5)
full_corr_test = np.clip(chosen_model.predict(F_test), -best["cap"], best["cap"])
full_test = np.clip(base_test + best["shrink"] * full_corr_test, 1.0, 8.5)
full_mae = print_metric("Full-fit chosen correction", y_phase, full_p1)

def save_submission(pred, filename, exact_fill=True):
    out = test[["SMILES", "Molecule Name"]].copy()
    out["pEC50"] = np.clip(np.asarray(pred, float), 1.0, 8.5)
    if exact_fill:
        known = dict(zip(phase1["Molecule Name"], phase1["pEC50"]))
        mask = out["Molecule Name"].isin(known)
        out.loc[mask, "pEC50"] = out.loc[mask, "Molecule Name"].map(known)
    csv = SUBS / filename
    out.to_csv(csv, index=False)
    try:
        out.to_parquet(csv.with_suffix(".parquet"), index=False)
    except Exception:
        pass
    print("saved:", csv, flush=True)
    print("rows:", len(out), "NaNs:", int(out["pEC50"].isna().sum()),
          "finite:", bool(np.isfinite(out["pEC50"]).all()), flush=True)
    print(out["pEC50"].describe(), flush=True)
    return csv

guarded_path = save_submission(full_test, "big_push_guarded_aux_residual.csv", exact_fill=True)

# A slightly higher-upside file: blend the full-fit correction with the CV OOF gain strength.
