    f.write(f"Full-fit residual: MAE={full_mae:.6f} RAE={full_mae / DENOM_RAE:.6f}\n\n")
    f.write(f"Residual cfg: model={best['model']} shrink={best['shrink']} cap={best['cap']}\n\n")
    f.write("Components:\n")
    for c in sorted(components, key=lambda z: z["mae"]):
        f.write(f"- {c['name']}: MAE={c['mae']:.6f} RAE={c['mae'] / DENOM_RAE:.6f}\n")
