print(f"repeated-CV MAE/RAE:{cv_mae:.6f} / {cv_mae / DENOM_RAE:.6f}", flush=True)
print(f"nested-CV MAE/RAE:  {nested_mae:.6f} / {nested_mae / DENOM_RAE:.6f}", flush=True)
print(f"full-fit MAE/RAE:   {full_mae:.6f} / {full_mae / DENOM_RAE:.6f}", flush=True)
