def nan_clean_train_test(Xtr, Xph, Xte):
    med = np.nanmedian(Xtr, axis=0)
    med = np.where(np.isfinite(med), med, 0.0)
    def clean(X):
        X = np.asarray(X, dtype=np.float32)
        bad = ~np.isfinite(X)
        if bad.any():
            X = X.copy()
            rows, cols = np.where(bad)
            X[rows, cols] = med[cols]
        return X
    return clean(Xtr), clean(Xph), clean(Xte)

def save_npy(path, arr):
    path = Path(path)
    np.save(path, np.asarray(arr, dtype=np.float32))
    return path

def load_npy(path):
    path = Path(path)
    return np.load(path) if path.exists() else None

# ---------------------------------------------------------------------------
# PXR-inspired 2D/3D descriptor block
# ---------------------------------------------------------------------------

def smarts_count(mol, smarts):
    patt = Chem.MolFromSmarts(smarts)
    if mol is None or patt is None:
        return 0.0
    return float(len(mol.GetSubstructMatches(patt)))

def pxr_alerts(mol):
    if mol is None:
        return np.zeros(24, dtype=np.float32)
    atoms = mol.GetAtoms()
    hal = sum(1 for a in atoms if a.GetAtomicNum() in [9, 17, 35, 53])
    aromatic_atoms = sum(1 for a in atoms if a.GetIsAromatic())
    vals = [
        hal,
        sum(1 for a in atoms if a.GetAtomicNum() == 9),
        smarts_count(mol, "C(F)(F)F"),
        smarts_count(mol, "S(=O)(=O)N"),
        smarts_count(mol, "C(=O)N"),
        smarts_count(mol, "C(=O)O"),
        smarts_count(mol, "c1ccccc1"),
        smarts_count(mol, "n1ccccc1"),
        smarts_count(mol, "[nH]1cccc1"),
        smarts_count(mol, "n1cc[nH]c1"),
        smarts_count(mol, "n1nncc1"),
        smarts_count(mol, "N(C)(C)"),
        smarts_count(mol, "O1CCNCC1"),
        smarts_count(mol, "C#N"),
        smarts_count(mol, "Oc1ccccc1"),
        smarts_count(mol, "c1ccc(cc1)-c2ccccc2"),
        smarts_count(mol, "C1CCC2C(C1)CCC3C2CCC4=CCCCC34"),
        smarts_count(mol, "[#6][#6][#6][#6][#6][#6][#6][#6]"),
        float(aromatic_atoms),
        float(Descriptors.NumAromaticRings(mol)),
        float(Descriptors.NumAliphaticRings(mol)),
        float(Descriptors.FractionCSP3(mol)),
        float(Descriptors.NumRotatableBonds(mol)),
        float(Descriptors.MolLogP(mol)),
    ]
    return np.asarray(vals, dtype=np.float32)

desc2d_fns = [
    Descriptors.MolWt, Descriptors.ExactMolWt, Descriptors.MolLogP, Descriptors.MolMR,
    Descriptors.TPSA, Descriptors.LabuteASA, Descriptors.NumHDonors,
    Descriptors.NumHAcceptors, Descriptors.NumRotatableBonds,
    Descriptors.HeavyAtomCount, Descriptors.RingCount, Descriptors.NumAromaticRings,
    Descriptors.NumAliphaticRings, Descriptors.NumSaturatedRings,
    Descriptors.NumHeteroatoms, Descriptors.NumValenceElectrons,
    Descriptors.NHOHCount, Descriptors.NOCount, Descriptors.FractionCSP3,
    Descriptors.BertzCT, Descriptors.BalabanJ, Descriptors.Kappa1,
    Descriptors.Kappa2, Descriptors.Kappa3, Descriptors.Chi0v,
    Descriptors.Chi1v, Descriptors.Chi2v, Descriptors.PEOE_VSA1,
    Descriptors.PEOE_VSA6, Descriptors.PEOE_VSA12, Descriptors.SlogP_VSA1,
    Descriptors.SlogP_VSA6, Descriptors.SlogP_VSA12, Descriptors.SMR_VSA1,
    Descriptors.SMR_VSA6, Descriptors.EState_VSA1, Descriptors.EState_VSA10,
]

def make_pxr_descriptor_matrix(smiles_list):
    cache = MOON / "pxr_2d3d_descriptors.npy"
    if cache.exists():
        arr = np.load(cache)
        if arr.shape[0] == len(smiles_list):
            print("loaded cached PXR descriptors:", arr.shape, flush=True)
            return arr
    morgan_gen = rdFingerprintGenerator.GetMorganGenerator(radius=2, fpSize=2048)
    rows = []
    for i, smi in enumerate(smiles_list):
        mol = Chem.MolFromSmiles(str(smi))
        if mol is None:
            rows.append(np.zeros(2048 + 167 + len(desc2d_fns) + 24 + 12, dtype=np.float32))
            continue
        bv = morgan_gen.GetFingerprint(mol)
        morgan = np.zeros((2048,), dtype=np.int8)
        DataStructs.ConvertToNumpyArray(bv, morgan)
        mk = MACCSkeys.GenMACCSKeys(mol)
        maccs = np.zeros((167,), dtype=np.int8)
        DataStructs.ConvertToNumpyArray(mk, maccs)
        d2 = []
        for fn in desc2d_fns:
            try:
                d2.append(float(fn(mol)))
            except Exception:
                d2.append(0.0)
        alerts = pxr_alerts(mol)
        d3 = np.zeros(12, dtype=np.float32)
        if RUN_3D_DESCRIPTORS and Descriptors3D is not None:
            try:
                mh = Chem.AddHs(mol)
                params = AllChem.ETKDGv3()
                params.randomSeed = 1729 + i
                params.useRandomCoords = False
                ok = AllChem.EmbedMolecule(mh, params)
                if ok == 0:
                    try:
                        AllChem.MMFFOptimizeMolecule(mh, maxIters=80)
                    except Exception:
                        pass
                    e = 0.0
                    try:
                        props = AllChem.MMFFGetMoleculeProperties(mh)
                        ff = AllChem.MMFFGetMoleculeForceField(mh, props)
                        e = float(ff.CalcEnergy()) if ff is not None else 0.0
                    except Exception:
                        e = 0.0
                    d3 = np.asarray([
                        Descriptors3D.Asphericity(mh),
                        Descriptors3D.Eccentricity(mh),
                        Descriptors3D.InertialShapeFactor(mh),
                        Descriptors3D.NPR1(mh),
                        Descriptors3D.NPR2(mh),
                        Descriptors3D.PMI1(mh),
                        Descriptors3D.PMI2(mh),
                        Descriptors3D.PMI3(mh),
                        Descriptors3D.RadiusOfGyration(mh),
                        Descriptors3D.SpherocityIndex(mh),
                        e,
                        e / max(float(mh.GetNumAtoms()), 1.0),
                    ], dtype=np.float32)
            except Exception:
                pass
        rows.append(np.concatenate([morgan.astype(np.float32), maccs.astype(np.float32), np.asarray(d2, dtype=np.float32), alerts, d3]))
        if (i + 1) % 500 == 0:
            print("PXR descriptors", i + 1, "/", len(smiles_list), flush=True)
    arr = np.vstack(rows).astype(np.float32)
    np.save(cache, arr)
    print("computed PXR descriptors:", arr.shape, flush=True)
    return arr

feature_blocks = []
pxr_all = make_pxr_descriptor_matrix(unique_smiles)
feature_blocks.append(("pxr_2d3d_pharm", pxr_all[idx_train], pxr_all[idx_phase], pxr_all[idx_test]))

# ---------------------------------------------------------------------------
# Independent molecular foundation-model embeddings
# ---------------------------------------------------------------------------

def mean_pool(last_hidden, attention_mask):
    mask = attention_mask[..., None].astype(np.float32)
    return (last_hidden * mask).sum(axis=1) / np.maximum(mask.sum(axis=1), 1.0)

def transformer_embed(model_id, label, smiles_list, batch_size=32, trust_remote_code=True):
    cache = MOON / f"{label}_emb.npy"
    got = load_npy(cache)
    if got is not None and got.shape[0] == len(smiles_list):
        print("loaded cached", label, got.shape, flush=True)
        return got
    # Transformer dependencies are expected to be installed by setup_openadmet_uv_env.sh.
    import torch
    from transformers import AutoModel, AutoTokenizer
    device = "cuda" if torch.cuda.is_available() else "cpu"
    print(f"loading transformer {label}: {model_id} on {device}", flush=True)
    tok = AutoTokenizer.from_pretrained(model_id, trust_remote_code=trust_remote_code)
    model = AutoModel.from_pretrained(model_id, trust_remote_code=trust_remote_code)
    model.to(device)
    model.eval()
    outs = []
    with torch.no_grad():
        for start in range(0, len(smiles_list), batch_size):
            batch = smiles_list[start:start + batch_size]
            enc = tok(batch, padding=True, truncation=True, max_length=256, return_tensors="pt")
            enc = {k: v.to(device) for k, v in enc.items()}
            out = model(**enc)
            hidden = out.last_hidden_state.detach().cpu().numpy()
            mask = enc["attention_mask"].detach().cpu().numpy()
            emb = mean_pool(hidden, mask)
            outs.append(emb.astype(np.float32))
            if (start // batch_size + 1) % 20 == 0:
                print(label, "embedded", min(start + batch_size, len(smiles_list)), "/", len(smiles_list), flush=True)
    arr = np.vstack(outs).astype(np.float32)
    save_npy(cache, arr)
    print("computed", label, arr.shape, flush=True)
    return arr

if RUN_TRANSFORMER_EMBEDDINGS:
    transformer_candidates = [
        ("chemberta_mtr", "DeepChem/ChemBERTa-77M-MTR", 32, True),
        ("chemberta_zinc", "seyonec/ChemBERTa-zinc-base-v1", 32, True),
    ]
    if RUN_MOLFORMER:
        transformer_candidates.append(("molformer_xl", "ibm/MoLFormer-XL-both-10pct", 16, True))
    for label, model_id, bs, trust in transformer_candidates:
        try:
            emb = transformer_embed(model_id, label, unique_smiles, batch_size=bs, trust_remote_code=trust)
            if np.isfinite(emb).all() and not np.allclose(emb, 0):
                feature_blocks.append((label, emb[idx_train], emb[idx_phase], emb[idx_test]))
        except Exception as exc:
            print("skip transformer", label, repr(exc), flush=True)

if RUN_UNIMOL2_BEST_EFFORT:
    try:
        for _logger_name in ["numba", "numba.core", "numba.core.byteflow", "httpcore", "httpx", "unimol_tools"]:
            logging.getLogger(_logger_name).setLevel(logging.ERROR)
        # Optional Uni-Mol dependency is expected to be installed by setup_openadmet_uv_env.sh.
        for _logger_name in ["numba", "numba.core", "numba.core.byteflow", "httpcore", "httpx", "unimol_tools"]:
            logging.getLogger(_logger_name).setLevel(logging.ERROR)
        from unimol_tools import UniMolRepr
        cache = MOON / "unimol2_repr.npy"
        emb = load_npy(cache)
        if emb is None or emb.shape[0] != len(unique_smiles):
            print("trying Uni-Mol2 SMILES repr path", flush=True)
            clf = UniMolRepr(data_type="molecule", remove_hs=False, model_name="unimolv2")
            reps = []
            for start in range(0, len(unique_smiles), 64):
                batch = unique_smiles[start:start + 64]
                rep = clf.get_repr(batch, return_atomic_reprs=False)
                arr = None
                if isinstance(rep, dict):
                    for key in ["cls_repr", "molecular_reprs", "mol_repr", "repr"]:
                        if key in rep:
                            arr = np.asarray(rep[key], dtype=np.float32)
                            break
                if arr is None:
                    arr = np.asarray(rep, dtype=np.float32)
                if arr.ndim != 2 or arr.shape[0] != len(batch):
                    raise RuntimeError(f"bad Uni-Mol2 repr shape {arr.shape}")
                reps.append(arr)
                print("Uni-Mol2 embedded", min(start + 64, len(unique_smiles)), "/", len(unique_smiles), flush=True)
            emb = np.vstack(reps).astype(np.float32)
            if np.allclose(emb, 0):
                raise RuntimeError("Uni-Mol2 returned all-zero embeddings")
            save_npy(cache, emb)
        feature_blocks.append(("unimol2_repr", emb[idx_train], emb[idx_phase], emb[idx_test]))
    except Exception as exc:
        print("skip Uni-Mol2 best-effort leg:", repr(exc), flush=True)

print("\nFeature blocks ready:", [b[0] for b in feature_blocks], flush=True)

# ---------------------------------------------------------------------------
# Turn each independent representation into a transfer component.
# ---------------------------------------------------------------------------

def model_candidates_for_block(label, n_features):
    seed = int(zlib.crc32(label.encode("utf-8")) % 10000)
    models = [
        ("ridge", make_pipeline(StandardScaler(), Ridge(alpha=10.0))),
        ("huber", make_pipeline(StandardScaler(), HuberRegressor(alpha=0.02, epsilon=1.35, max_iter=2000))),
        ("lgb_l1", LGBMRegressor(
            objective="regression_l1",
            n_estimators=450,
            learning_rate=0.025,
            num_leaves=15,
            min_child_samples=18,
            subsample=0.85,
            colsample_bytree=0.70,
            reg_lambda=12.0,
            random_state=100 + seed,
            n_jobs=-1,
            verbose=-1,
        )),
        ("extra", ExtraTreesRegressor(
            n_estimators=500,
            max_features=0.45,
            min_samples_leaf=4,
            random_state=200 + seed,
            n_jobs=-1,
        )),
    ]
    if XGBRegressor is not None:
        models.append(("xgb_l1", XGBRegressor(
            objective="reg:squarederror",
            n_estimators=300,
            max_depth=3,
            learning_rate=0.025,
            subsample=0.85,
            colsample_bytree=0.70,
            reg_lambda=18.0,
            min_child_weight=10.0,
            random_state=300 + seed,
            n_jobs=-1,
            verbosity=0,
        )))
    return models

def fit_transfer_component(label, Xtr0, Xph0, Xte0):
    Xtr, Xph, Xte = nan_clean_train_test(Xtr0, Xph0, Xte0)
    bins = pd.qcut(y_phase, q=5, labels=False, duplicates="drop")
    outer = StratifiedKFold(n_splits=5, shuffle=True, random_state=710)
    best = None
    for model_name, proto in model_candidates_for_block(label, Xtr.shape[1]):
        try:
            oof = np.zeros(len(y_phase), dtype=float)
            test_repeats = []
            for fold, (trp, vap) in enumerate(outer.split(Xph, bins), start=1):
                import copy
                model = copy.deepcopy(proto)
                X_fit = np.vstack([Xtr, Xph[trp]])
                y_fit = np.concatenate([y_train, y_phase[trp]])
                model.fit(X_fit, y_fit)
                oof[vap] = np.clip(model.predict(Xph[vap]), 1.0, 8.5)
                test_repeats.append(np.clip(model.predict(Xte), 1.0, 8.5))
            score = mae(y_phase, oof)
            print(f"component {label}/{model_name}: MAE={score:.6f} RAE={score / DENOM_RAE:.6f}", flush=True)
            if best is None or score < best["mae"]:
                best = {"label": label, "model_name": model_name, "proto": proto, "oof": oof, "mae": score, "test_cv": np.mean(test_repeats, axis=0)}
        except Exception as exc:
            print(f"skip model {label}/{model_name}: {repr(exc)}", flush=True)
    if best is None:
        raise RuntimeError(f"all models failed for feature block {label}")
    import copy
    final_model = copy.deepcopy(best["proto"])
    final_model.fit(np.vstack([Xtr, Xph]), np.concatenate([y_train, y_phase]))
    best["test"] = np.clip(final_model.predict(Xte), 1.0, 8.5)
    print("BEST component", label, best["model_name"], "MAE", best["mae"], "RAE", best["mae"] / DENOM_RAE, flush=True)
    return best

components = [{"name": base_name, "oof": base_oof, "test": base_test, "mae": base_nested}]
for label, Xtr, Xph, Xte in feature_blocks:
    try:
        comp = fit_transfer_component(label, Xtr, Xph, Xte)
        if np.isfinite(comp["oof"]).all() and comp["mae"] < 0.75:
            components.append({"name": label + "/" + comp["model_name"], "oof": comp["oof"], "test": comp["test"], "mae": comp["mae"]})
    except Exception as exc:
        print("skip component block", label, repr(exc), flush=True)

print("\n=== Component summary ===", flush=True)
for c in sorted(components, key=lambda z: z["mae"]):
    print(f"{c['name']}: MAE={c['mae']:.6f} RAE={c['mae'] / DENOM_RAE:.6f}", flush=True)

# ---------------------------------------------------------------------------
# Nested blend audit. This is the only selector allowed to decide the final.
# ---------------------------------------------------------------------------

P = np.column_stack([c["oof"] for c in components])
T = np.column_stack([c["test"] for c in components])
names = [c["name"] for c in components]

def simplex_weights(Pfit, yfit, max_weight=0.70, l2=0.003):
    n = Pfit.shape[1]
    if n == 1:
        return np.ones(1)
    x0 = np.ones(n) / n
    bounds = [(0.0, max_weight)] * n
    cons = [{"type": "eq", "fun": lambda w: np.sum(w) - 1.0}]
    def obj(w):
        return np.mean(np.abs(yfit - Pfit @ w)) + l2 * float(np.sum(w * w))
    res = minimize(obj, x0, method="SLSQP", bounds=bounds, constraints=cons, options={"maxiter": 1000, "ftol": 1e-10})
    w = np.clip(res.x, 0, max_weight)
    if w.sum() <= 0:
        w = x0
    else:
        w = w / w.sum()
    return w

bins = pd.qcut(y_phase, q=5, labels=False, duplicates="drop")
nested = StratifiedKFold(n_splits=5, shuffle=True, random_state=911)
blend_oof = np.zeros(len(y_phase), dtype=float)
fold_weights = []
for fold, (trp, vap) in enumerate(nested.split(P, bins), start=1):
    w = simplex_weights(P[trp], y_phase[trp], max_weight=0.70, l2=0.006)
    blend_oof[vap] = np.clip(P[vap] @ w, 1.0, 8.5)
    fold_weights.append(w)
    print("blend fold", fold, {names[i]: round(float(w[i]), 4) for i in range(len(names)) if w[i] > 1e-4}, flush=True)

blend_nested = metric("MOONSHOT nested blend", y_phase, blend_oof)
full_w = simplex_weights(P, y_phase, max_weight=0.70, l2=0.006)
moon_test = np.clip(T @ full_w, 1.0, 8.5)
moon_phase_diag = np.clip(P @ full_w, 1.0, 8.5)
full_diag = metric("MOONSHOT full-OOF-weight diagnostic", y_phase, moon_phase_diag)

print("full weights:", {names[i]: round(float(full_w[i]), 5) for i in range(len(names)) if full_w[i] > 1e-5}, flush=True)

def save_submission(pred, filename):
    out = test[["SMILES", "Molecule Name"]].copy()
    out["pEC50"] = np.clip(np.asarray(pred, float), 1.0, 8.5)
    phase_map = dict(zip(phase1["Molecule Name"], phase1["pEC50"]))
    mask = out["Molecule Name"].isin(phase_map)
    out.loc[mask, "pEC50"] = out.loc[mask, "Molecule Name"].map(phase_map)
    path = SUBS / filename
    out.to_csv(path, index=False)
    try:
        out.to_parquet(path.with_suffix(".parquet"), index=False)
    except Exception:
        pass
    shutil.copy2(path, ROOT / filename)
    print("saved:", path, flush=True)
    print("copied:", ROOT / filename, flush=True)
    print("rows:", len(out), "NaNs:", int(out.pEC50.isna().sum()), "finite:", bool(np.isfinite(out.pEC50).all()), flush=True)
    print(out.pEC50.describe(), flush=True)
    return path

moon_path = None
if blend_nested + 0.001 < base_nested:
    moon_path = save_submission(moon_test, "MOONSHOT_FINAL_RECOMMENDED.csv")
    decision = "GREEN: independent representation blend beat guarded baseline under nested audit."
else:
    # Still save a candidate for inspection, but keep the safer master file as recommended.
    moon_path = save_submission(moon_test, "MOONSHOT_EXPERIMENTAL_NOT_RECOMMENDED.csv")
    master = SUBS / "MASTER_FINAL_RECOMMENDED.csv"
    if master.exists():
        shutil.copy2(master, SUBS / "MOONSHOT_FINAL_RECOMMENDED.csv")
        shutil.copy2(master, ROOT / "MOONSHOT_FINAL_RECOMMENDED.csv")
        moon_path = SUBS / "MOONSHOT_FINAL_RECOMMENDED.csv"
    decision = "NO GREEN: moonshot did not clear nested threshold; recommended file remains guarded master."

report = SUBS / "moonshot_parallel_research_report.md"
with open(report, "w", encoding="utf-8") as f:
    f.write("# Moonshot Parallel Research Extension Report\n\n")
    f.write(f"Base: {base_name} MAE={base_nested:.6f} RAE={base_nested / DENOM_RAE:.6f}\n\n")
    f.write(f"Moonshot nested blend: MAE={blend_nested:.6f} RAE={blend_nested / DENOM_RAE:.6f}\n\n")
    f.write(f"Moonshot full diagnostic: MAE={full_diag:.6f} RAE={full_diag / DENOM_RAE:.6f}\n\n")
    f.write("Components:\n")
    for c in sorted(components, key=lambda z: z["mae"]):
        f.write(f"- {c['name']}: MAE={c['mae']:.6f} RAE={c['mae'] / DENOM_RAE:.6f}\n")
    f.write("\nFull weights:\n")
    for i, name in enumerate(names):
        if full_w[i] > 1e-5:
            f.write(f"- {name}: {float(full_w[i]):.6f}\n")
    f.write(f"\nDecision: {decision}\n")

print("\n=== MOONSHOT DECISION ===", flush=True)
print("base nested:", base_nested, base_nested / DENOM_RAE, flush=True)
print("moonshot nested:", blend_nested, blend_nested / DENOM_RAE, flush=True)
print("moonshot diagnostic:", full_diag, full_diag / DENOM_RAE, flush=True)
print(decision, flush=True)
print("recommended file:", moon_path, flush=True)
print("report:", report, flush=True)